INSERT INTO `v1_a129c493332e865ab5ae16532c450682ad64eb9cdd24d9675a7f71fb3d2cc069` VALUES (0.0, "2030/12/17 14:59:59", 0.0, 0, 1, 10040, 102601, "リン", "あたしだって\nやるときはやるよ！", 0.0, 24001, "2020/04/30 12:00:00", 1, 24);
INSERT INTO `v1_a129c493332e865ab5ae16532c450682ad64eb9cdd24d9675a7f71fb3d2cc069` VALUES (0.0, "2030/12/17 14:59:59", 0.0, 1, 1, 10040, 102601, "リン", "ふぅ…\nこれであたしの仕事は\n終わりだね", 0.0, 24002, "2020/04/30 12:00:00", 1, 24);
INSERT INTO `v1_a129c493332e865ab5ae16532c450682ad64eb9cdd24d9675a7f71fb3d2cc069` VALUES (0.0, "2030/12/17 14:59:59", 0.0, 2, 1, 10040, 102601, "リン", "終わった終わった\n一人でもなんとか\nなるもんだね", 0.0, 24003, "2020/04/30 12:00:00", 1, 24);
INSERT INTO `v1_a129c493332e865ab5ae16532c450682ad64eb9cdd24d9675a7f71fb3d2cc069` VALUES (0.0, "2030/12/17 14:59:59", 0.0, 3, 2, 10040, 102601, "リン", "やったね！\nこれでようやく\nサボれるよ…", 0.0, 24004, "2020/04/30 12:00:00", 2, 24);
INSERT INTO `v1_a129c493332e865ab5ae16532c450682ad64eb9cdd24d9675a7f71fb3d2cc069` VALUES (0.0, "2030/12/17 14:59:59", 0.0, 4, 1, 10040, 102601, "リン", "チーズが欲しいなら\nきちんと働いて\n買いに来なよ", 0.0, 24005, "2020/04/30 12:00:00", 1, 24);
INSERT INTO `v1_a129c493332e865ab5ae16532c450682ad64eb9cdd24d9675a7f71fb3d2cc069` VALUES (0.0, "2030/12/17 14:59:59", 0.0, 5, 2, 10040, 102601, "リン", "あたしを敵に回した\n恐ろしさ\n思い知ったか！", 0.0, 24006, "2020/04/30 12:00:00", 2, 24);
INSERT INTO `v1_a129c493332e865ab5ae16532c450682ad64eb9cdd24d9675a7f71fb3d2cc069` VALUES (0.0, "2030/12/17 14:59:59", 0.0, 6, 2, 10040, 102601, "リン", "あたしも意外と\nやるもんでしょ？", 0.0, 24007, "2020/04/30 12:00:00", 2, 24);
INSERT INTO `v1_a129c493332e865ab5ae16532c450682ad64eb9cdd24d9675a7f71fb3d2cc069` VALUES (0.0, "2030/12/17 14:59:59", 0.0, 7, 4, 10040, 102601, "リン", "疲れた…\nねずみの逃げ足\n速すぎるよ…", 0.0, 24008, "2020/04/30 12:00:00", 4, 24);
INSERT INTO `v1_a129c493332e865ab5ae16532c450682ad64eb9cdd24d9675a7f71fb3d2cc069` VALUES (0.0, "2030/12/17 14:59:59", 0.0, 8, 4, 10040, 102601, "リン", "このままじゃ\nまっひ～に\n叱られちゃうよ", 0.0, 24009, "2020/04/30 12:00:00", 4, 24);
INSERT INTO `v1_a129c493332e865ab5ae16532c450682ad64eb9cdd24d9675a7f71fb3d2cc069` VALUES (0.0, "2030/12/17 14:59:59", 0.0, 9, 4, 10040, 102601, "リン", "まじめに\nやったんだけどな…\n悔しいな～", 0.0, 24010, "2020/04/30 12:00:00", 4, 24);
INSERT INTO `v1_a129c493332e865ab5ae16532c450682ad64eb9cdd24d9675a7f71fb3d2cc069` VALUES (0.0, "2030/12/17 14:59:59", 0.0, 10, 4, 10040, 102601, "リン", "やられた…\nねずみって意外と\nてごわいね", 0.0, 24011, "2020/04/30 12:00:00", 4, 24);
INSERT INTO `v1_a129c493332e865ab5ae16532c450682ad64eb9cdd24d9675a7f71fb3d2cc069` VALUES (0.0, "2030/12/17 14:59:59", 0.0, 11, 4, 10040, 102601, "リン", "おのれ～\nあたしのチーズを\n盗みやがって～！", 0.0, 24012, "2020/04/30 12:00:00", 4, 24);
INSERT INTO `v1_a129c493332e865ab5ae16532c450682ad64eb9cdd24d9675a7f71fb3d2cc069` VALUES (0.0, "2030/12/17 14:59:59", 0.0, 12, 1, 10040, 102601, "リン", "疲れた…\nけど、次こそは\n守り抜くよ…", 1.81, 24013, "2020/04/30 12:00:00", 4, 24);
